// === FACIS PV subflow physics ===============================================
// Mirrors src/simulators/pv_generation/simulator.py.
// Keep tests/flows/pv.spec.js in sync.

const STC = 1000.0; // W/m² Standard Test Conditions

const DEFAULT_CFG = {
    system_id: 'pv-default',
    nominal_capacity_kwp: 50.0,
    noct_c: 45.0,
    temperature_coefficient_pct_per_c: -0.4,
    reference_temperature_c: 25.0,
    system_losses_percent: 14.0,
    interval_minutes: 15
};

function moduleTemperature(ambientC, ghiWm2, cfg) {
    if (ghiWm2 <= 0) return ambientC;
    const noctRise = (cfg.noct_c - 20.0) * (ghiWm2 / 800.0);
    return ambientC + noctRise;
}

function temperatureDerating(moduleTempC, cfg) {
    const diff = moduleTempC - cfg.reference_temperature_c;
    const derating = 1.0 + (cfg.temperature_coefficient_pct_per_c / 100.0) * diff;
    return Math.max(0.0, Math.min(1.2, derating));
}

function powerOutput(ghiWm2, moduleTempC, cfg) {
    if (ghiWm2 <= 0) return 0.0;
    const irrFactor = ghiWm2 / STC;
    const tempFactor = temperatureDerating(moduleTempC, cfg);
    const lossFactor = 1.0 - (cfg.system_losses_percent / 100.0);
    const power = cfg.nominal_capacity_kwp * irrFactor * tempFactor * lossFactor;
    return Math.min(power, cfg.nominal_capacity_kwp);
}

function efficiencyPercent(powerKw, ghiWm2, cfg) {
    if (ghiWm2 <= 0 || powerKw <= 0) return 0.0;
    const theoretical = cfg.nominal_capacity_kwp * (ghiWm2 / STC);
    if (theoretical <= 0) return 0.0;
    return Math.min(100.0, (powerKw / theoretical) * 100.0);
}

function utcDateKey(isoTs) {
    return isoTs.slice(0, 10); // YYYY-MM-DD
}

function generatePv(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'pv-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const siteId = payload.site_id || '';
    const cfg = Object.assign({}, DEFAULT_CFG, payload.config || {});
    const weather = payload.weather || { conditions: { ghi_w_m2: 0, temperature_c: 15 } };

    const ghi = (weather.conditions && typeof weather.conditions.ghi_w_m2 === 'number')
        ? weather.conditions.ghi_w_m2 : 0;
    const ambient = (weather.conditions && typeof weather.conditions.temperature_c === 'number')
        ? weather.conditions.temperature_c : 15;

    const moduleT = moduleTemperature(ambient, ghi, cfg);
    const power = powerOutput(ghi, moduleT, cfg);
    const efficiency = efficiencyPercent(power, ghi, cfg);

    // Daily energy accumulation in flow context, keyed by entity + date.
    const dateKey = utcDateKey(isoTs);
    const dailyKey = 'pv_daily';
    const all = flow.get(dailyKey) || {};
    const entityState = all[entityId] || { date: dateKey, kwh: 0 };
    if (entityState.date !== dateKey) {
        entityState.date = dateKey;
        entityState.kwh = 0;
    }
    const intervalH = (cfg.interval_minutes || 15) / 60.0;
    entityState.kwh += power * intervalH;
    all[entityId] = entityState;
    flow.set(dailyKey, all);

    return {
        site_id: siteId,
        system_id: cfg.system_id || entityId,
        timestamp: isoTs,
        readings: {
            power_output_kw: power,
            daily_energy_kwh: entityState.kwh,
            irradiance_w_m2: ghi,
            module_temperature_c: moduleT,
            efficiency_percent: efficiency
        }
    };
}

msg.payload = generatePv(msg.payload || {});
return msg;
